import { useState } from 'react';
import { Link } from 'react-router-dom';

const Header = () => {
  const [menuOpen, setMenuOpen] = useState(false);

  const toggleMenu = () => setMenuOpen(!menuOpen);

  return (
    <header className="sticky top-0 z-50 bg-gray-950 text-white shadow-md">
      <div className="max-w-6xl mx-auto px-4 flex items-center justify-between h-16">
        <Link to="/" className="text-lg font-semibold tracking-tight">ShoeStore</Link>
        <nav className="hidden md:flex items-center gap-6">
          <Link to="/men" className="text-sm hover:text-indigo-400 transition">Men</Link>
          <Link to="/women" className="text-sm hover:text-indigo-400 transition">Women</Link>
          <Link to="/kids" className="text-sm hover:text-indigo-400 transition">Kids</Link>
          <Link to="/accessories" className="text-sm hover:text-indigo-400 transition">Accessories</Link>
          <div className="relative">
            <input type="text" placeholder="Search..." className="px-3 py-1 rounded-lg bg-gray-800 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500" />
          </div>
          <Link to="/wishlist" className="text-sm hover:text-indigo-400 transition">Wishlist</Link>
          <Link to="/cart" className="text-sm hover:text-indigo-400 transition">Cart</Link>
        </nav>
        <button className="md:hidden text-gray-400 hover:text-white" onClick={toggleMenu}>
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d={menuOpen ? "M6 18L18 6M6 6l12 12" : "M4 6h16M4 12h16M4 18h16"} />
          </svg>
        </button>
      </div>
      {menuOpen && (
        <div className="md:hidden bg-gray-950 border-t border-gray-800 px-4 py-3 flex flex-col gap-3">
          <Link to="/men" className="text-sm text-gray-300 hover:text-white">Men</Link>
          <Link to="/women" className="text-sm text-gray-300 hover:text-white">Women</Link>
          <Link to="/kids" className="text-sm text-gray-300 hover:text-white">Kids</Link>
          <Link to="/accessories" className="text-sm text-gray-300 hover:text-white">Accessories</Link>
          <Link to="/wishlist" className="text-sm text-gray-300 hover:text-white">Wishlist</Link>
          <Link to="/cart" className="text-sm text-gray-300 hover:text-white">Cart</Link>
        </div>
      )}
    </header>
  );
};

export default Header;

