interface CartItemProps {
  item: {
    id: string;
    name: string;
    price: number;
    quantity: number;
    image: string;
  };
}

const CartItem = ({ item }: CartItemProps) => (
  <div className="flex items-center gap-4 p-4 bg-gray-800 rounded-xl">
    <img src={item?.image || "https://images.unsplash.com/photo-1506744038136-46273834b3fb?w=400"} alt={item?.name ?? "Item Image"} className="w-16 h-16 object-cover rounded-lg" />
    <div className="flex-1">
      <h4 className="text-white font-medium">{item?.name ?? "Unknown Item"}</h4>
      <p className="text-gray-400 text-sm">${item?.price?.toFixed(2) ?? "0.00"}</p>
      <div className="flex items-center gap-2 mt-2">
        <button className="px-2 py-1 rounded-lg bg-gray-700 text-white hover:bg-gray-600 transition">-</button>
        <span className="text-white">{item?.quantity ?? 0}</span>
        <button className="px-2 py-1 rounded-lg bg-gray-700 text-white hover:bg-gray-600 transition">+</button>
      </div>
    </div>
    <button className="px-2 py-1 rounded-lg bg-red-600 text-white hover:bg-red-500 transition">Remove</button>
  </div>
);

export default CartItem;

